class Solution:
    def numberOfSpecialChars(self, word: str) -> int:
        lower_set = set()
        upper_set = set()
        count = 0

        for char in word:
            if char.islower():
                lower_set.add(char)
            else:
                upper_set.add(char.lower())

        for char in upper_set:
            if char in lower_set:
                count += 1

        return count
